window.PACTO.acts["reg-2013-1309"]={"label": "REGOLAMENTO (UE) N. 1309/2013 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 1309/2013", "file": "ext-reg-2013-1309.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/reg/2013/1309/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Obiettivi", "anchor": "art_1", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento istituisce il Fondo europeo di adeguamento alla globalizzazione (FEG) per la durata del quadro finanziario pluriennale dal 1<span class=\"oj-super\">o</span> gennaio 2014 al 31 dicembre 2020.</p>"], [null, "<p class=\"oj-normal\">Lo scopo del FEG è di contribuire a una crescita economica intelligente, inclusiva e sostenibile, nonché di promuovere un'occupazione sostenibile nell'Unione consentendo a quest'ultima di dimostrare solidarietà e sostegno ai lavoratori collocati in esubero e ai lavoratori autonomi la cui attività sia cessata in conseguenza di trasformazioni rilevanti della struttura del commercio mondiale dovute alla globalizzazione, a causa del persistere della crisi finanziaria ed economica globale oggetto del regolamento (CE) n. 546/2009 oppure a causa di una nuova crisi economica e finanziaria globale.</p>"], [null, "<p class=\"oj-normal\">Le azioni che beneficiano dei contributi finanziari a valere sul FEG hanno lo scopo di garantire che il maggior numero possibile dei beneficiari che partecipano a tali azioni trovino quanto prima e comunque entro il periodo di sei mesi previsto per la trasmissione della relazione finale di cui all'articolo 18, paragrafo 2, un'occupazione sostenibile.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Ambito di applicazione", "anchor": "art_2", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento si applica alle domande presentate dagli Stati membri per contributi finanziari a valere sul FEG a favore di azioni indirizzate a:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dei lavoratori collocati in esubero e dei lavoratori autonomi la cui attività sia cessata in conseguenza di trasformazioni rilevanti della struttura del commercio mondiale dovute alla globalizzazione, dimostrate in particolare da un sostanziale aumento delle importazioni nell'Unione, da un cambiamento radicale del commercio di beni e servizi nell'Unione, da un rapido declino della quota di mercato dell'Unione in un determinato settore o da una delocalizzazione di attività verso paesi terzi, a condizione che tali esuberi abbiano un impatto negativo di rilievo sull'economia locale, regionale o nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dei lavoratori collocati in esubero e dei lavoratori autonomi la cui attività sia cessata a causa del persistere della crisi finanziaria ed economica globale affrontata nel regolamento (CE) n. 546/2009 oppure a causa di una nuova crisi finanziaria ed economica globale.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "3": {"label": "Articolo 3", "heading": "Definizioni", "anchor": "art_3", "frags": [[null, "<p class=\"oj-normal\">Ai fini del presente regolamento, per beneficiario si intende:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un lavoratore il cui contratto di lavoro si sia concluso anticipatamente per collocamento in esubero oppure giunto a scadenza nel corso del periodo di riferimento di cui all'articolo 4 e non rinnovato;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un lavoratore autonomo che abbia impiegato un massimo di dieci lavoratori che erano stati collocati in esubero nell'ambito di applicazione del presente regolamento e la cui attività sia cessata, a condizione che quest'ultima dipendesse in maniera dimostrabile dall'impresa di cui all'articolo 4, paragrafo 1, lettera a), oppure che, ai sensi dell'articolo 4, paragrafo 1, lettera b), il lavoratore autonomo operasse nel settore economico in questione.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "4": {"label": "Articolo 4", "heading": "Criteri di intervento", "anchor": "art_4", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Si concede un contributo finanziario a valere sul FEG quando sussistono le condizioni stabilite all'articolo 2 e hanno come conseguenza:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il collocamento in esubero di almeno 500 lavoratori o la cessazione dell'attività di lavoratori autonomi, nell'arco di un periodo di riferimento di quattro mesi, in un'impresa di uno Stato membro, compresi i lavoratori collocati in esubero e i lavoratori autonomi la cui attività sia cessata alle imprese dei fornitori o dei produttori a valle dell'impresa in questione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il collocamento in esubero di almeno 500 lavoratori o la cessazione dell'attività di lavoratori autonomi, nell'arco di un periodo di riferimento di nove mesi, in particolare in PMI, tutte operanti nello stesso settore economico definito a livello delle divisioni della NACE revisione 2, in una regione o due regioni contigue di livello NUTS 2, oppure in più di due regioni contigue di livello NUTS 2, a condizione che il numero complessivo di lavoratori o di lavoratori autonomi in due regioni combinate sia superiore a 500.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nei di mercati del lavoro di dimensioni ridotte o in circostanze eccezionali debitamente giustificate dallo Stato membro che ha presentato la domanda, in particolare per quanto concerne le domande collettive che coinvolgono le PMI, una domanda di contributo finanziario a titolo del presente articolo può essere considerata ricevibile anche se i criteri fissati al paragrafo 1, lettere a) o b), non sono completamente soddisfatti, laddove gli esuberi abbiano un grave impatto sull'occupazione e sull'economia locale, regionale o nazionale. Lo Stato membro richiedente precisa quale dei criteri d'intervento stabiliti al paragrafo 1, lettere a) e b), non è interamente soddisfatto. L'importo cumulato dei contributi in circostanze eccezionali non può eccedere il 15 % dell'importo annuo massimo del FEG.</p>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Calcolo degli esuberi e delle cessazioni di attività", "anchor": "art_5", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Lo Stato membro richiedente precisa il metodo utilizzato per calcolare, ai fini dell'articolo 4, il numero di lavoratori e di lavoratori autonomi di cui all'articolo 3.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Lo Stato membro richiedente è tenuto a calcolare il numero di cui al paragrafo 1 a decorrere da una delle seguenti date:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dalla data in cui il datore di lavoro, conformemente all'articolo 3, paragrafo 1, della direttiva 98/59/CE del Consiglio (<span class=\"oj-super oj-note-tag\">7</span>), notifica il piano di collocamento in esubero collettivo all'autorità pubblica competente per iscritto; in tal caso, lo Stato membro che ha presentato la domanda fornisce ulteriori informazioni alla Commissione sul numero reale di lavoratori collocati in esubero conformemente all'articolo 4, paragrafo 1, del presente regolamento prima del completamento della valutazione da parte della Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dalla data in cui il datore di lavoro notifica il preavviso di licenziamento o di risoluzione del contratto di lavoro al singolo lavoratore;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dalla data della risoluzione di fatto del contratto di lavoro o della sua scadenza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dalla fine dell'incarico presso l'impresa utilizzatrice; oppure</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per i lavoratori autonomi, dalla data di cessazione delle attività determinata conformemente alle disposizioni legislative o amministrative nazionali.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Beneficiari ammissibili", "anchor": "art_6", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Lo Stato membro richiedente può offrire servizi personalizzati cofinanziati dal FEG ai beneficiari ammissibili, che possono comprendere:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i lavoratori collocati in esubero e i lavoratori autonomi la cui attività sia cessata, calcolati conformemente all'articolo 5, durante il periodo di riferimento previsto all'articolo 4;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i lavoratori collocati in esubero e i lavoratori autonomi la cui attività sia cessata, calcolati conformemente all'articolo 5, prima o dopo il periodo di riferimento di cui all'articolo 4, paragrafo 1, lettera a), o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i lavoratori collocati in esubero e i lavoratori autonomi la cui attività sia cessata, se una domanda presentata a norma dell'articolo 4, paragrafo 2, non risponde ai criteri stabiliti dall'articolo 4, paragrafo 1, lettera a).</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">I lavoratori e i lavoratori autonomi di cui al primo comma, lettere b) e c), sono considerati ammissibili, a condizione che siano collocati in esubero o che la loro attività sia cessata dopo la notifica generale del progetto di licenziamento e a condizione che possa essere stabilito un chiaro nesso causale con l'evento da cui hanno avuto origine gli esuberi durante il periodo di riferimento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   In deroga all'articolo 2, gli Stati membri richiedenti possono, fino al 31 dicembre 2017, fornire servizi personalizzati cofinanziati dal FEG per un determinato numero di NEET di età inferiore ai 25 anni o, qualora gli Stati membri lo decidano, di età inferiore ai 30 anni, alla data di presentazione della domanda, uguale al numero dei beneficiari interessati, dando la priorità ai collocati in esubero o la cui attività sia cessata, a condizione che almeno una parte degli esuberi ai sensi dell'articolo 3 sia ubicata in regioni di livello NUTS 2 ammissibili nell'ambito dell'iniziativa a favore dell'occupazione giovanile. Il sostegno può essere fornito ai NEET di età inferiore ai 25 anni o, qualora gli Stati membri lo decidano, di età inferiore ai 30 anni, nelle regioni di livello NUTS 2 ammissibili nell'ambito dell'iniziativa a favore dell'occupazione giovanile.</p>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Azioni ammissibili", "anchor": "art_7", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Può essere concesso un contributo finanziario a valere sul FEG per misure attive del mercato del lavoro che si iscrivono in un pacchetto coordinato di servizi personalizzati volti a facilitare la reintegrazione nel mercato del lavoro dipendente o autonomo dei beneficiari interessati, in particolare i disoccupati svantaggiati, giovani e meno giovani. Il pacchetto coordinato di servizi personalizzati può comprendere in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la formazione e la riqualificazione su misura anche per quanto riguarda le competenze nel campo delle tecnologie dell'informazione e della comunicazione e la certificazione dell'esperienza acquisita, l'assistenza nella ricerca di un lavoro, l'orientamento professionale, i servizi di consulenza, il tutoraggio, l'assistenza al ricollocamento, la promozione dell'imprenditorialità, l'aiuto alle attività professionali autonome, alla creazione e al rilevamento di imprese da parte dei dipendenti nonché le attività di cooperazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">misure speciali di durata limitata, quali le indennità per la ricerca di un lavoro, gli incentivi all'assunzione destinati ai datori di lavoro, le indennità di mobilità, le indennità di soggiorno o di formazione (comprese le indennità di assistenza);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">misure volte a incentivare in particolare i disoccupati svantaggiati, giovani e meno giovani, a rimanere o ritornare nel mercato del lavoro.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">I costi delle misure di cui alla lettera b) non possono superare il 35 % dei costi totali per il pacchetto coordinato dei servizi personalizzati elencati nel presente paragrafo.</p>\n<p class=\"oj-normal\">Il costo degli investimenti per le attività indipendenti e la creazione nonché il rilevamento di imprese da parte dei dipendenti non può superare i 15 000 EUR.</p>\n<p class=\"oj-normal\">La progettazione del pacchetto coordinato di servizi personalizzati dovrebbe tenere conto delle prospettive future del mercato del lavoro e delle competenze richieste. Il pacchetto coordinato dovrebbe essere compatibile con il passaggio a un'economia sostenibile nonché efficiente sotto il profilo delle risorse.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le seguenti misure non sono ammissibili a un contributo finanziario a valere sul FEG:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le misure speciali di durata limitata di cui al paragrafo 1, lettera b), che non sono condizionali alla partecipazione attiva dei beneficiari interessati ad attività di ricerca di lavoro e di formazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le misure che rientrano nella sfera di responsabilità delle imprese in virtù del diritto nazionale o di contratti collettivi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Le azioni sostenute dal FEG non sostituiscono le misure passive di protezione sociale.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il pacchetto coordinato di servizi personalizzati è elaborato in consultazione con i beneficiari interessati, i loro rappresentanti o le parti sociali.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Su iniziativa dello Stato membro che ha presentato la domanda, può essere concesso un contributo finanziario a valere sul FEG per le attività di preparazione, gestione, informazione e pubblicità, nonché di controllo e di rendicontazione.</p>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Domande", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Lo Stato membro richiedente presenta una domanda alla Commissione entro dodici settimane dalla data in cui sono soddisfatti i criteri stabiliti all'articolo 4, paragrafo 1 o 2.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro due settimane dalla data di presentazione della domanda o, se del caso, dalla data in cui la Commissione dispone della traduzione della stessa, se posteriore, la Commissione notifica la ricezione della domanda e comunica allo Stato membro eventuali ulteriori informazioni ancora necessarie per la relativa valutazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In caso di richiesta di ulteriori informazioni da parte della Commissione, lo Stato membro risponde entro sei settimane dalla data della richiesta. Su richiesta debitamente motivata dello Stato membro interessato, la Commissione proroga detto termine di due settimane.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Sulla base delle informazioni fornite dallo Stato membro la Commissione conclude la valutazione della conformità della domanda alle condizioni per la concessione di un contributo finanziario entro dodici settimane a decorrere dal ricevimento della domanda completa o, se del caso, della traduzione della stessa. In via eccezionale, in caso di impossibilità per la Commissione di rispettare detto termine, essa ne fornisce una spiegazione per iscritto indicando le motivazioni del ritardo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Una domanda completa contiene le seguenti informazioni:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un'analisi motivata del collegamento tra gli esuberi o la cessazione dell'attività e le trasformazioni rilevanti nella struttura del commercio mondiale o il grave deterioramento della situazione economica locale, regionale e nazionale in seguito alla globalizzazione o al persistere della crisi finanziaria ed economica globale oppure a una nuova crisi finanziaria ed economica globale. Detta analisi è basata su statistiche e altre informazioni del livello più appropriato per dimostrare il rispetto dei criteri d'intervento stabiliti all'articolo 4;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la conferma che l'impresa che ha proceduto al licenziamento, qualora le sue attività siano proseguite anche in seguito a tale provvedimento, abbia adempiuto agli obblighi di legge in materia di esuberi accordando ai propri lavoratori tutte le prestazioni previste;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una valutazione del numero di esuberi conformemente all'articolo 5 e una spiegazione degli eventi all'origine degli esuberi stessi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'identificazione, se del caso, delle imprese, dei fornitori o dei produttori a valle e dei settori che licenziano, nonché delle categorie di beneficiari interessate, ripartite per sesso e fascia di età;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli effetti previsti degli esuberi sull'economia e sull'occupazione a livello locale, regionale o nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una descrizione del pacchetto coordinato di servizi personalizzati e delle relative spese, comprese in particolare le eventuali misure a sostegno delle iniziative per l'occupazione dei beneficiari svantaggiati, giovani e meno giovani;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una spiegazione in merito alla complementarità del pacchetto di misure rispetto alle azioni finanziate da altri fondi nazionali o dell'Unione, nonché informazioni sulle iniziative che rivestono un carattere obbligatorio per le imprese interessate in virtù del diritto nazionale o di contratti collettivi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una stima dei costi per ciascuna delle componenti del pacchetto coordinato di servizi personalizzati a sostegno dei beneficiari interessati e di qualunque attività di preparazione, gestione, informazione e pubblicità, controllo e rendicontazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le date di avvio, effettive o previste, dei servizi personalizzati rivolti ai beneficiari interessati e delle attività per l'attuazione del FEG, quali definite all'articolo 7, paragrafi 1 e 4 rispettivamente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le procedure seguite per la consultazione dei beneficiari interessati, dei loro rappresentanti o delle parti sociali nonché delle autorità locali e regionali o eventualmente di altre organizzazioni interessate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una dichiarazione di conformità dell'assistenza FEG richiesta alle norme procedurali e sostanziali dell'Unione in materia di aiuti di Stato, nonché una dichiarazione che spieghi i motivi per cui i servizi personalizzati non si sostituiscono alle misure che rientrano nella sfera di responsabilità delle imprese in virtù del diritto nazionale o di contratti collettivi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le fonti nazionali di prefinanziamento o cofinanziamento e, se del caso, altri tipi di cofinanziamento.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Complementarità, conformità e coordinamento", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I contributi finanziari a valere sul FEG non sostituiscono le azioni che rientrano nella sfera di responsabilità delle imprese in virtù del diritto nazionale o di contratti collettivi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'assistenza a favore dei beneficiari interessati integra le azioni realizzate dagli Stati membri a livello nazionale, regionale e locale, comprese quelle cofinanziate da fondi dell'Unione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il contributo finanziario a valere sul FEG è limitato al minimo necessario per garantire solidarietà e sostegno temporaneo, una tantum, ai beneficiari interessati. Le azioni sostenute dal FEG sono conformi al diritto dell'Unione e nazionale, anche per quanto concerne le norme in materia di aiuti di Stato.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Conformemente alle loro rispettive responsabilità, la Commissione e lo Stato membro che ha presentato la domanda garantiscono il coordinamento dell'assistenza fornita dei fondi dell'Unione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Lo Stato membro che ha presentato la domanda garantisce che le azioni specifiche che ricevono un contributo finanziario a valere sul FEG non ricevano assistenza anche da altri strumenti finanziari dell'Unione.</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Uguaglianza tra uomini e donne e non-discriminazione", "anchor": "art_10", "frags": [[null, "<p class=\"oj-normal\">La Commissione e gli Stati membri garantiscono che tanto l'uguaglianza tra uomini e donne quanto l'integrazione della prospettiva di genere rappresentino un elemento costitutivo delle varie tappe di attuazione del contributo finanziario a valere sul FEG, promosso in ognuna di esse. La Commissione e gli Stati membri adottano tutte le opportune misure per prevenire qualunque discriminazione basata sul sesso, l'origine razziale o etnica, la religione o le convinzioni, una disabilità, l'età o l'orientamento sessuale nelle varie tappe dell'attuazione del contributo finanziario e nell'accesso al FEG.</p>"]]}, "11": {"label": "Articolo 11", "heading": "Assistenza tecnica su iniziativa della Commissione", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Su iniziativa della Commissione, un massimo dello 0,5 % dell'importo annuo massimo del FEG può essere utilizzato per finanziare attività di preparazione, di monitoraggio, di raccolta dati e di creazione di una base di conoscenze pertinenti per l'attuazione del FEG, che può altresì essere utilizzato per finanziare il sostegno amministrativo e tecnico, così come attività di informazione e comunicazione, nonché l'audit, il controllo e la valutazione necessari all'applicazione del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro i limiti del tetto fissato al paragrafo 1, il Parlamento europeo e il Consiglio rendono disponibile, all'inizio di ogni anno e sulla base di una proposta della Commissione, un importo destinato all'assistenza tecnica.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I compiti di cui al paragrafo 1 sono eseguiti conformemente al regolamento finanziario e alle modalità di esecuzione applicabili a tale modalità di esecuzione del bilancio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'assistenza tecnica della Commissione comprende la fornitura di informazioni e di orientamenti agli Stati membri per l'utilizzo, il monitoraggio e la valutazione del FEG. La Commissione dovrebbe anche fornire informazioni nonché chiari orientamenti sul ricorso al FEG alle parti sociali europee e nazionali.</p>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Informazione, comunicazione e pubblicità", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Lo Stato membro richiedente fornisce informazioni e pubblicizza le azioni finanziate. Tali informazioni sono destinate ai beneficiari interessati, alle autorità locali e regionali, alle parti sociali, ai mezzi di comunicazione e al pubblico generale e valorizzano il ruolo dell'Unione e garantiscono la visibilità del contributo a valere sul FEG.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione gestisce e aggiorna regolarmente un sito internet, accessibile in tutte le lingue ufficiali delle istituzioni dell'Unione, per fornire informazioni aggiornate sul FEG, orientamenti per la presentazione delle domande e informazioni sulle domande accettate e respinte nonché sul ruolo del Parlamento europeo e del Consiglio nell'ambito della procedura di bilancio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione realizza attività di informazione e comunicazione sui casi di intervento del FEG e sui risultati ottenuti sulla base della sua esperienza, allo scopo di migliorare l'efficacia del FEG e di assicurare che i cittadini e i lavoratori dell'Unione siano al corrente della sua esistenza. La Commissione riferisce ogni due anni in merito al ricorso al FEG per paese e per settore.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le risorse destinate alle azioni di comunicazione a titolo del presente regolamento contribuiscono a coprire anche la comunicazione istituzionale delle priorità politiche dell'Unione, nella misura in cui abbiano un rapporto con gli obiettivi generali del presente regolamento.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Determinazione del contributo finanziario", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Sulla base della valutazione effettuata conformemente all'articolo 8 e tenuto conto in particolare del numero di beneficiari interessati, delle azioni proposte e dei costi previsti, la Commissione stima e propone il più rapidamente possibile l'importo del contributo finanziario a valere sul FEG che è eventualmente possibile concedere, nei limiti delle risorse disponibili. Tale importo non può superare il 60 % del totale dei costi previsti di cui all'articolo 8, paragrafo 5, lettera h).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Se, sulla base della valutazione effettuata conformemente all'articolo 8, la Commissione giunge alla conclusione che sono soddisfatte le condizioni per la concessione di un contributo finanziario ai sensi del presente regolamento, essa avvia immediatamente la procedura di cui all'articolo 15.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Se, sulla base della valutazione effettuata conformemente all'articolo 8, la Commissione giunge alla conclusione che non sono soddisfatte le condizioni per la concessione di un contributo finanziario ai sensi del presente regolamento, ne informa immediatamente lo Stato membro che ha presentato la domanda.</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Spese ammissibili", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Sono ammissibili a un contributo finanziario a valere sul FEG le spese sostenute a decorrere dalle date fissate nella domanda ai sensi dell'articolo 8, paragrafo 5, lettera i), in cui lo Stato membro interessato inizia, o dovrebbe iniziare, a fornire servizi personalizzati ai beneficiari interessati o a sostenere le spese amministrative per l'attuazione del FEG, a norma dell'articolo 7, paragrafi 1 e 4, rispettivamente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Per quanto riguarda le sovvenzioni si applicano, a seconda dei casi, gli articoli 67 e 68 del regolamento (UE, Euratom) n. 1303/2013 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">8</span>) e l'articolo 14 del regolamento (UE, Euratom) n. 1304/2013 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">9</span>), nonché gli eventuali atti delegati adottati dalla Commissione ai sensi di tali regolamenti.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Procedura di bilancio", "anchor": "art_15", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le modalità del FEG sono conformi al punto 13 dell'accordo interistituzionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli stanziamenti concernenti il FEG sono iscritti nel bilancio generale dell'Unione a titolo di accantonamento.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione, da un lato, e il Parlamento europeo e il Consiglio, dall'altro, si adoperano per ridurre al minimo i tempi di mobilitazione del FEG.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Se la Commissione ha concluso che sono soddisfatte le condizioni per fornire un contributo finanziario a valere sul FEG presenta una proposta di mobilitazione. La decisione di mobilitare il FEG è adottata congiuntamente dal Parlamento europeo e dal Consiglio entro un mese dalla presentazione della proposta agli stessi. Il Consiglio delibera a maggioranza qualificata e il Parlamento europeo delibera alla maggioranza dei suoi componenti e dei tre quinti dei voti espressi.</p>\n<p class=\"oj-normal\">Contemporaneamente alla presentazione della proposta di decisione di mobilitazione del FEG, la Commissione presenta al Parlamento europeo e al Consiglio una proposta di storno verso le pertinenti linee di bilancio. In caso di disaccordo, è avviata una procedura di trilogo.</p>\n<p class=\"oj-normal\">Gli storni relativi al FEG sono effettuati conformemente all'articolo 27 del regolamento finanziario.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Contemporaneamente all'adozione di una proposta di decisione di mobilitazione del FEG, la Commissione adotta una decisione di concessione di un contributo finanziario, mediante un atto di esecuzione, che entra in vigore alla data di adozione della decisione di mobilitazione del FEG da parte del Parlamento europeo e del Consiglio.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Una proposta di decisione di mobilitazione del FEG conforme al paragrafo 4 comprende quanto segue:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la valutazione realizzata conformemente all'articolo 8, paragrafo 4, accompagnata da una sintesi delle informazioni sulle quali si basa;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli elementi comprovanti il rispetto dei criteri stabiliti agli articoli 4 e 9; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i motivi che giustificano gli importi proposti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Pagamento e utilizzo del contributo finanziario", "anchor": "art_16", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   In seguito all'entrata in vigore di una decisione di concessione di un contributo finanziario conformemente all'articolo 15, paragrafo 5, la Commissione versa, in linea di principio entro 15 giorni, il contributo finanziario allo Stato membro interessato in un'unico pagamento di prefinanziamento pari al 100 %. Il prefinanziamento è oggetto di liquidazione contabile al momento della chiusura del contributo finanziario conformemente all'articolo 18, paragrafo 2.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il contributo finanziario di cui al paragrafo 1 è attuato a norma della gestione concorrente, conformemente all'articolo 59 del regolamento finanziario.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le condizioni dettagliate di finanziamento a livello tecnico sono definite dalla Commissione nella decisione di concessione del contributo finanziario di cui all'articolo 15, paragrafo 5.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Lo Stato membro realizza le azioni ammissibili di cui all'articolo 7 il prima possibile e comunque entro 24 mesi dalla data di presentazione della domanda presentata conformemente all'articolo 8, paragrafo 1.</p>\n<p class=\"oj-normal\">Lo Stato membro può decidere di posticipare l'avvio delle azioni ammissibili per un massimo di tre mesi dalla data di presentazione della domanda. In caso di posticipo le azioni ammissibili sono attuate entro 24 mesi dalla data di avvio comunicata dallo Stato membro nella domanda.</p>\n<p class=\"oj-normal\">Nel caso in cui i beneficiari accedano a corsi di istruzione o formazione di durata uguale o superiore a due anni, i costi di tali corsi possono rientrare nel cofinanziamento a valere sul FEG fino allo scadere del termine per la presentazione della relazione finale di cui all'articolo 18, paragrafo 1, a condizione che detti costi siano stati sostenuti prima di tale data.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Al momento dell'esecuzione delle azioni comprese nel pacchetto di servizi personalizzati, lo Stato membro interessato può presentare alla Commissione una proposta di modifica di tali azioni aggiungendo altre azioni ammissibili di cui all'articolo 7, paragrafo 1, lettere a) e c), a condizione che tali modifiche siano debitamente giustificate e che il totale non superi il contributo finanziario di cui all'articolo 15, paragrafo 5. La Commissione valuta le modifiche proposte e, in caso di accordo, ne informa lo Stato membro.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Le spese di cui all'articolo 7, paragrafo 4, sono ammissibili fino allo scadere del termine per la presentazione della relazione finale.</p>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Utilizzo dell'euro", "anchor": "art_17", "frags": [[null, "<p class=\"oj-normal\">Nelle domande, decisioni di concessione di un contributo finanziario e relazioni ai sensi del presente regolamento, e in qualunque altro documento afferente, tutti gli importi sono espressi in euro.</p>"]]}, "18": {"label": "Articolo 18", "heading": "Relazione finale e chiusura", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro sei mesi dalla scadenza del termine di cui all'articolo 16, paragrafo 4, lo Stato membro interessato presenta alla Commissione una relazione finale sull'attuazione del contributo finanziario comprendente informazioni:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sul tipo di azione e i principali risultati ottenuti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sui nomi degli organismi responsabili dell'esecuzione del pacchetto di misure nello Stato membro;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sulle caratteristiche dei beneficiari interessati e sul loro status occupazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sull'eventualità che l'impresa, salvo che si tratti di microimpresa e PMI, abbia beneficiato di aiuti di Stato o di precedenti finanziamenti a valere sul Fondo di coesione o dei fondi strutturali dell'Unione nei cinque anni precedenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una dichiarazione giustificativa delle spese indicante, ove possibile, la complementarità delle azioni con quelle finanziate dal Fondo sociale europeo (FSE).</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Ove possibile, i dati relativi ai beneficiari sono ripartiti per sesso.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro sei mesi dalla ricezione di tutte le informazioni richieste conformemente al paragrafo 1 da parte della Commissione, quest'ultima procede alla chiusura del contributo finanziario a valere sul FEG determinandone l'importo finale ed eventualmente il saldo dovuto dallo Stato membro interessato in applicazione dell'articolo 22.</p>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Relazione biennale", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 1<span class=\"oj-super\">o</span> agosto 2015 e ogni due anni da tale data, la Commissione presenta al Parlamento europeo e al Consiglio una relazione quantitativa e qualitativa completa sulle attività realizzate a titolo del presente regolamento e del regolamento (CE) n. 1927/2006 nel corso dei due anni precedenti. Tale relazione verte principalmente sui risultati ottenuti dal FEG e contiene, in particolare, informazioni sulle domande presentate, le decisioni adottate, le azioni finanziate, compresi i i dati statistici relativi al reinserimento professionale dei beneficiari assistiti per Stato membro e la complementarità di tali azioni con le azioni finanziate da altri fondi dell'Unione, in particolare il FSE e informazioni sulla chiusura dei contributi finanziari concessi. Essa dovrebbe comprendere inoltre informazioni sulle domande che sono state respinte o ridimensionate per mancanza di stanziamenti sufficienti o a causa di non ammissibilità.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La relazione è trasmessa per informazione alla Corte dei conti, al Comitato economico e sociale europeo, al Comitato delle regioni e alle parti sociali.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Valutazione", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione effettua, di propria iniziativa e in stretta collaborazione con gli Stati membri:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una valutazione intermedia dell'efficacia e della sostenibilità dei risultati raggiunti entro il 30 giugno 2017; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una valutazione ex-post, entro il 31 dicembre 2021, con l'assistenza di esperti esterni, intesa a misurare l'impatto del FEG e il suo valore aggiunto.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I risultati delle valutazioni di cui al paragrafo 1 sono trasmessi per informazione al Parlamento europeo, al Consiglio, alla Corte dei conti, al Comitato economico e sociale europeo, al Comitato delle regioni e alle parti sociali. Le raccomandazioni contenute nelle valutazioni dovrebbero essere prese in considerazione in sede di progettazione di nuovi programmi nel settore dell'occupazione e degli affari sociali.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le valutazioni di cui al paragrafo 1 includono i dati indicanti il numero di domande e contemplano i risultati ottenuti dal FEG per paese e per settore, ai fini della verifica dell'effettivo raggiungimento dei destinatari previsti da parte del FEG.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Gestione e controllo finanziario", "anchor": "art_21", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatta salva la responsabilità della Commissione in materia di esecuzione del bilancio generale dell'Unione, gli Stati membri sono responsabili in prima istanza della gestione delle azioni che beneficiano del sostegno del FEG nonché del controllo finanziario di tali azioni. A tale scopo, adottano in particolare le seguenti misure:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">verificare che i meccanismi di gestione e di controllo siano posti in essere e applicati in modo tale da garantire un utilizzo efficace e corretto dei fondi dell'Unione, conformemente ai principi di sana gestione finanziaria;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">verificare la corretta esecuzione delle azioni finanziate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantire che le spese finanziate si basino su documenti giustificativi verificabili e siano legali e regolari;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prevenire, individuare e correggere le irregolarità, quali definite all'articolo 122 del regolamento (UE, Euratom) n1303/2013 e recuperare le somme indebitamente versate, eventualmente aumentate degli interessi di mora. Gli Stati membri notificano qualunque irregolarità in tal senso alla Commissione e la mantengono informata dell'evoluzione di eventuali procedimenti amministrativi e giudiziari.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri designano gli organismi responsabili della gestione e del controllo delle azioni sostenute dal FEG conformemente all'articolo 59, paragrafo 3, del regolamento finanziario nonché ai criteri e alle procedure definiti nel regolamento (UE, Euratom) n. 1303/2013. Al momento della presentazione della relazione finale di cui all'articolo 18 del presente regolamento, tali organismi designati forniscono alla Commissione le informazioni di cui all'articolo 59, paragrafo 5, del regolamento finanziario relative all'attuazione del contributo finanziario.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Qualora accertino un'irregolarità, gli Stati membri apportano le necessarie rettifiche finanziarie. Tali rettifiche consistono nell'annullare in tutto o in parte il contributo finanziario. Gli Stati membri recuperano le somme indebitamente versate in seguito alle irregolarità individuate e le rimborsano alla Commissione; se la somma non è rimborsata dallo Stato membro interessato entro il termine stabilito, si applicano interessi di mora.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nell'esercizio della sua responsabilità in materia di esecuzione del bilancio generale dell'Unione, la Commissione adotta ogni misura necessaria per verificare che le azioni finanziate siano realizzate nel rispetto dei principi di sana ed efficace gestione finanziaria. Spetta allo Stato membro richiedente garantire l'esistenza e il corretto funzionamento di sistemi di gestione e controllo. La Commissione verifica l'esistenza di tali sistemi.</p>\n<p class=\"oj-normal\">A tale scopo, fatte salve le competenze della Corte dei conti o i controlli effettuati dallo Stato membro conformemente alle disposizioni legislative, regolamentari e amministrative nazionali, possono essere effettuati da funzionari o agenti della Commissione controlli in loco, anche a campione, sulle azioni finanziate dal FEG, con un preavviso minimo di un giorno lavorativo. La Commissione ne informa lo Stato membro che ha presentato la domanda, in modo da ottenere tutta l'assistenza necessaria. Possono partecipare a tali controlli anche funzionari o agenti dello Stato membro interessato.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri garantiscono che tutti i documenti giustificativi riguardanti le spese sostenute siano mantenuti a disposizione della Commissione e della Corte dei conti per un periodo di tre anni dalla chiusura di un contributo finanziario ricevuto a valere sul FEG.</p>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Rimborso del contributo finanziario", "anchor": "art_22", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Nei casi in cui il costo reale di un'azione sia inferiore all'importo stimato, iscritto a bilancio conformemente all'articolo 15, la Commissione adotta una decisione, mediante un atto di esecuzione, con la quale impone allo Stato membro interessato di rimborsare la parte corrispondente del contributo finanziario ricevuto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel caso in cui lo Stato membro interessato venga meno agli obblighi enunciati nella decisione di concessione di un contributo finanziario, la Commissione intraprende le misure necessarie, adottando una decisione mediante un atto di esecuzione per imporre a detto Stato membro di rimborsare in tutto o in parte il contributo finanziario ricevuto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Prima dell'adozione di una decisione ai sensi del paragrafo 1 o 2, la Commissione esamina opportunamente il fascicolo e, in particolare, concede allo Stato membro interessato un termine preciso per comunicare le sue osservazioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Se, dopo aver proceduto alle necessarie verifiche, la Commissione giunge alla conclusione che lo Stato membro non si è conformato agli obblighi a esso incombenti in virtù dell'articolo 21, paragrafo 1, essa, entro tre mesi dalla scadenza del periodo di cui al paragrafo 3, decide, laddove non sia raggiunto un accordo e lo Stato membro non abbia apportato le rettifiche entro il termine fissato dalla stessa Commissione nonché tenendo conto delle eventuali osservazioni dello Stato membro, di procedere alle necessarie rettifiche finanziarie annullando in tutto o in parte il contributo del FEG all'azione in questione. Le somme indebitamente versate in seguito alle irregolarità individuate sono recuperate; se la somma non è rimborsata dallo Stato membro che ha presentato la domanda entro il termine stabilito, si applicano interessi di mora.</p>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Abrogazione", "anchor": "art_23", "frags": [[null, "<p class=\"oj-normal\">Il regolamento (CE) n. 1927/2006 è abrogato con effetto dal 1<span class=\"oj-super\">o</span> gennaio 2014.</p>"], [null, "<p class=\"oj-normal\">In deroga al primo comma, esso continua ad applicarsi alle domande presentate entro il 31 dicembre 2013.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Entrata in vigore", "anchor": "art_24", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento entra in vigore il giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span>.</p>"], [null, "<p class=\"oj-normal\">Esso si applica alle domande presentate tra il 1<span class=\"oj-super\">o</span> gennaio 2014 e il 31 dicembre 2020.</p>"]]}}, "recitals": {}};